function evenOnlyFilter(input: readonly number[]): readonly number[] {
  if (input.length > 256) {
    throw new RangeError(`Input array exceeds maximum length of 256, got ${input.length}`);
  }

  for (let i = 0; i < input.length; i++) {
    if (!Number.isSafeInteger(input[i])) {
      throw new TypeError(`Element at index ${i} is not a safe integer: ${input[i]}`);
    }
  }

  return input.filter(n => n % 2 === 0);
}

export { evenOnlyFilter };
export default evenOnlyFilter;
